        grunt.option('key', null);
        grunt.option('source', null);
    });
    grunt.config('nugetpush', {
        dist: {
            src: 'Moment.js.*.nupkg',
        },
    });
    grunt.config('clean.nuget', {
        src: 'Moment.js.*.nupkg',
    });

    grunt.registerTask('nuget-publish', [
        'nugetpack',
        'nugetkey_pre',
        'nugetkey',
        'nugetkey_post',
        'nugetpush',
        'clean:nuget',
    ]);
};

